     2→//! src/module_79.rs
     3→//!
     4→//! Quality-Control & Enrichment stage for ChirpPulse’s real-time ETL
     5→//!
     6→//! This module owns the “QC/Enrich” micro-service that sits right after
     7→//! raw ingestion.  It validates structural and business constraints,
     8→//! removes duplicates in a partially ordered fashion, enriches events
     9→//! with lightweight metadata (e.g. language codes already discovered by a
    10→//! previous stage), and forwards the passing events to the next Kafka
    11→//! topic.
    12→//!
    13→//! The code showcases several architectural patterns used across
    14→//! ChirpPulse:
    15→//!   • Pipeline Pattern—each rule implements `QualityRule` and runs in
    16→//!     parallel over an async stream.
    17→//!   • Strategy Pattern—rules can be hot-swapped at run-time without
    18→//!     stopping the pipeline.
    19→//!   • Observer Pattern—metrics are emitted for every rule and error.
    20→//!
    21→//! The implementation is fully asynchronous (Tokio) and production-grade
    22→//! with backpressure, cancellation and self-healing retry loops.
    23→
    24→#![allow(clippy::module_name_repetitions)]
    25→#![allow(dead_code)]
    26→
    27→use std::{
    28→    sync::Arc,
    29→    time::{Duration, SystemTime, UNIX_EPOCH},
    30→};
    31→
    32→use async_trait::async_trait;
    33→use bloom::{BloomFilter, ASMS};
    34→use dashmap::DashSet;
    35→use futures::{Stream, StreamExt};
    36→use metrics::{counter, histogram, increment_counter};
    37→use rdkafka::{
    38→    consumer::{Consumer, StreamConsumer},
    39→    message::BorrowedMessage,
    40→    producer::{FutureProducer, FutureRecord},
    41→    ClientConfig,
    42→};
    43→use serde::{Deserialize, Serialize};
    44→use tokio::{select, sync::RwLock, time};
    45→use tracing::{error, info, instrument, warn};
    46→
    47→/// The source Kafka topic where raw events arrive.
    48→const SOURCE_TOPIC: &str = "raw_social_events";
    49→/// The sink Kafka topic that receives validated events.
    50→const SINK_TOPIC: &str = "qc_valid_events";
    51→/// Topic for the dead-letter queue (invalid / unrecoverable).
    52→const DLQ_TOPIC: &str = "qc_dead_letter";
    53→
    54→/// The maximum amount of time the producer waits for Kafka acks.
    55→const PRODUCER_TIMEOUT_MS: u64 = 5000;
    56→
    57→/// Maximum number of past events to remember for duplicate detection.
    58→/// In a real system this would be sharded and/or backed by Redis.
    59→const DEDUP_CAPACITY: usize = 1_000_000;
    60→
    61→//
    62→// ───────────────────────────── Models ───────────────────────────────────────────
    63→//
    64→
    65→/// Minimal representation of a social interaction.
    66→#[derive(Debug, Clone, Serialize, Deserialize)]
    67→pub struct SocialEvent {
    68→    pub event_id: String,
    69→    pub user_id: String,
    70→    pub text: String,
    71→    pub lang: Option<String>,
    72→    pub created_at: u64, // epoch millis
    73→}
    74→
    75→/// Error emitted by quality-control rules.
    76→#[derive(thiserror::Error, Debug)]
    77→pub enum QualityError {
    78→    #[error("missing mandatory field: {0}")]
    79→    MissingField(&'static str),
    80→    #[error("text content is empty")]
    81→    EmptyText,
    82→    #[error("language unsupported: {0}")]
    83→    UnsupportedLanguage(String),
    84→    #[error("event already seen (duplicate)")]
    85→    Duplicate,
    86→    #[error("internal rule error: {0}")]
    87→    Internal(anyhow::Error),
    88→}
    89→
    90→/// Errors that invalidate producing to Kafka.
    91→/// These errors are sent to a DLQ to avoid stalling the pipeline.
    92→#[derive(thiserror::Error, Debug)]
    93→pub enum SinkError {
    94→    #[error("kafka produce error: {0}")]
    95→    Produce(String),
    96→    #[error("serialization error: {0}")]
    97→    Serialize(#[from] serde_json::Error),
    98→}
    99→
   100→/// Errors that may occur at the pipeline level.
   101→#[derive(thiserror::Error, Debug)]
   102→pub enum PipelineError {
   103→    #[error("source kafka error: {0}")]
   104→    Source(String),
   105→    #[error("sink error: {0}")]
   106→    Sink(#[from] SinkError),
   107→    #[error("rule error: {0}")]
   108→    Rule(#[from] QualityError),
   109→}
   110→
   111→//
   112→// ──────────────────────── Quality-control rules ────────────────────────────────
   113→//
   114→
   115→#[async_trait]
   116→pub trait QualityRule: Send + Sync + 'static {
   117→    /// Human-friendly rule name used in metrics/logs.
   118→    fn name(&self) -> &'static str;
   119→
   120→    /// Return `Ok(())` if the event passes validation/enrichment.
   121→    /// Otherwise return a `QualityError` describing the failure.
   122→    async fn check(&self, event: &mut SocialEvent) -> Result<(), QualityError>;
   123→}
   124→
   125→/// Ensures the `text` field is non-empty.
   126→pub struct NonEmptyText;
   127→
   128→#[async_trait]
   129→impl QualityRule for NonEmptyText {
   130→    fn name(&self) -> &'static str {
   131→        "non_empty_text"
   132→    }
   133→
   134→    async fn check(&self, event: &mut SocialEvent) -> Result<(), QualityError> {
   135→        if event.text.trim().is_empty() {
   136→            Err(QualityError::EmptyText)
   137→        } else {
   138→            Ok(())
   139→        }
   140→    }
   141→}
   142→
   143→/// Very small static allow-list of language codes for illustration.
   144→/// A real implementation would delegate to configuration / DB.
   145→pub struct LanguageAllowListRule {
   146→    allowed: &'static [&'static str],
   147→}
   148→
   149→impl LanguageAllowListRule {
   150→    pub const fn new(allowed: &'static [&'static str]) -> Self {
   151→        Self { allowed }
   152→    }
   153→}
   154→
   155→#[async_trait]
   156→impl QualityRule for LanguageAllowListRule {
   157→    fn name(&self) -> &'static str {
   158→        "language_allow_list"
   159→    }
   160→
   161→    async fn check(&self, event: &mut SocialEvent) -> Result<(), QualityError> {
   162→        let lang = event
   163→            .lang
   164→            .as_ref()
   165→            .ok_or(QualityError::MissingField("lang"))?;
   166→
   167→        if self.allowed.contains(&lang.as_str()) {
   168→            Ok(())
   169→        } else {
   170→            Err(QualityError::UnsupportedLanguage(lang.clone()))
   171→        }
   172→    }
   173→}
   174→
   175→/// Duplicate-detection using a Bloom filter plus exact check fallback.
   176→///
   177→/// The filter gives an O(1) approximate membership test with controllable
   178→/// false-positive rate.  We complement it with an exact check in the
   179→/// concurrent `DashSet` to eliminate false positives at the cost of
