   102→/// Trait representing any sentiment analysis algorithm.
   103→///
   104→/// The `analyze` function is async to allow network calls (e.g., model server).
   105→#[async_trait]
   106→pub trait SentimentStrategy: Send + Sync + 'static {
   107→    /// Identifier shown in telemetry and persisted to records.
   108→    fn name(&self) -> &'static str;
   109→
   110→    /// Perform sentiment analysis on the given message body.
   111→    async fn analyze(&self, text: &str) -> Result<SentimentScore, ProcessorError>;
   112→}
   113→
   114→/// Trivial implementation that returns neutral sentiment.
   115→/// Useful as a circuit-breaker fallback.
   116→pub struct NeutralStrategy;
   117→
   118→#[async_trait]
   119→impl SentimentStrategy for NeutralStrategy {
   120→    fn name(&self) -> &'static str {
   121→        "neutral"
   122→    }
   123→
   124→    async fn analyze(&self, _text: &str) -> Result<SentimentScore, ProcessorError> {
   125→        Ok(SentimentScore {
   126→            polarity: 0.0,
   127→            confidence: 0.0,
   128→            meta: None,
   129→        })
   130→    }
   131→}
   132→
   133→/// Example lexical strategy that looks for positive/negative keywords
   134→/// (purely demonstrative – not production grade).
   135→pub struct LexiconStrategy {
   136→    positives: Vec<&'static str>,
   137→    negatives: Vec<&'static str>,
   138→}
   139→
   140→impl Default for LexiconStrategy {
   141→    fn default() -> Self {
   142→        Self {
   143→            positives: vec!["good", "great", "love", "excellent", "happy"],
   144→            negatives: vec!["bad", "hate", "terrible", "awful", "sad"],
   145→        }
   146→    }
   147→}
   148→
   149→#[async_trait]
   150→impl SentimentStrategy for LexiconStrategy {
   151→    fn name(&self) -> &'static str {
   152→        "lexicon_v1"
   153→    }
   154→
   155→    async fn analyze(&self, text: &str) -> Result<SentimentScore, ProcessorError> {
   156→        let mut score = 0f32;
   157→        let mut hits = 0u32;
   158→
   159→        for token in text.split_whitespace() {
   160→            if self.positives.iter().any(|p| token.eq_ignore_ascii_case(p)) {
   161→                score += 1.0;
   162→                hits += 1;
   163→            } else if self.negatives.iter().any(|n| token.eq_ignore_ascii_case(n)) {
   164→                score -= 1.0;
   165→                hits += 1;
   166→            }
   167→        }
   168→
   169→        if hits == 0 {
   170→            // Unknown sentiment
   171→            return Ok(SentimentScore {
   172→                polarity: 0.0,
   173→                confidence: 0.0,
   174→                meta: None,
   175→            });
   176→        }
   177→
   178→        let polarity = (score / hits as f32).clamp(-1.0, 1.0);
   179→        Ok(SentimentScore {
   180→            polarity,
   181→            confidence: (hits as f32 / text.split_whitespace().count() as f32).clamp(0.0, 1.0),
   182→            meta: None,
   183→        })
   184→    }
   185→}
