   187→/// Registry containing all available strategies and the currently active default one.
   188→#[derive(Clone)]
   189→pub struct StrategyRegistry {
   190→    strategies: Arc<RwLock<HashMap<String, Arc<dyn SentimentStrategy>>>>,
   191→    default: Arc<RwLock<String>>,
   192→}
   193→
   194→impl StrategyRegistry {
   195→    pub fn new() -> Self {
   196→        let mut map: HashMap<String, Arc<dyn SentimentStrategy>> = HashMap::new();
   197→        let neutral = Arc::new(NeutralStrategy);
   198→        map.insert(neutral.name().to_owned(), neutral.clone());
   199→
   200→        let lex = Arc::new(LexiconStrategy::default());
   201→        map.insert(lex.name().to_owned(), lex.clone());
   202→
   203→        Self {
   204→            strategies: Arc::new(RwLock::new(map)),
   205→            default: Arc::new(RwLock::new(lex.name().to_owned())),
   206→        }
   207→    }
   208→
   209→    /// Register or override a strategy at runtime.
   210→    pub async fn register<S: SentimentStrategy>(&self, strategy: S) {
   211→        let name = strategy.name().to_owned();
   212→        self.strategies
   213→            .write()
   214→            .await
   215→            .insert(name, Arc::new(strategy));
   216→    }
   217→
   218→    /// Promote the named strategy to be the default going forward.
   219→    pub async fn promote_default(&self, name: &str) -> Result<(), ProcessorError> {
   220→        let read = self.strategies.read().await;
   221→        if read.contains_key(name) {
   222→            *self.default.write().await = name.to_owned();
   223→            Ok(())
   224→        } else {
   225→            Err(ProcessorError::StrategyNotFound(name.to_owned()))
   226→        }
   227→    }
   228→
   229→    /// Get the current default strategy.
   230→    pub async fn default(&self) -> Arc<dyn SentimentStrategy> {
   231→        let name = self.default.read().await.clone();
   232→        self.get(&name)
   233→            .await
   234→            .unwrap_or_else(|_| Arc::new(NeutralStrategy))
   235→    }
   236→
   237→    /// Fetch a strategy by name.
   238→    pub async fn get(&self, name: &str) -> Result<Arc<dyn SentimentStrategy>, ProcessorError> {
   239→        self.strategies
   240→            .read()
   241→            .await
   242→            .get(name)
   243→            .cloned()
   244→            .ok_or_else(|| ProcessorError::StrategyNotFound(name.into()))
   245→    }
   246→}
