    87→/// Trait implemented by all pipeline stages.
    88→#[async_trait]
    89→pub trait Stage: Send + Sync {
    90→    /// Human-readable name for logging & metrics.
    91→    fn name(&self) -> &'static str;
    92→
    93→    /// Process a single event.
    94→    ///
    95→    /// Returning `Ok(None)` drops the event (e.g. filtered-out languages).
    96→    /// Returning `Err(StageError::Transient)` tells the runner to retry the
    97→    /// event later; `Permanent` will skip the event.
    98→    async fn process(
