   104→/// A pipeline is an ordered collection of boxed stages.
   105→#[derive(Default)]
   106→pub struct Pipeline {
   107→    stages: Vec<Arc<dyn Stage>>,
   108→}
   109→
   110→impl Pipeline {
   111→    pub fn new() -> Self {
   112→        Self { stages: vec![] }
   113→    }
   114→
   115→    /// Adds a stage to the pipeline.  Stages are executed in the order they are
   116→    /// registered.
   117→    pub fn add_stage<T: Stage + 'static>(mut self, stage: T) -> Self {
   118→        self.stages.push(Arc::new(stage));
   119→        self
   120→    }
   121→
   122→    /// Run the event through each stage, short-circuiting on failure.
   123→    async fn execute(
   124→        &self,
   125→        event: EnrichedEvent,
   126→    ) -> Result<Option<EnrichedEvent>, StageError> {
   127→        let mut current = Some(event);
   128→        for stage in &self.stages {
   129→            match current {
   130→                Some(ev) => match stage.process(ev,).await {
   131→                    Ok(next) => current = next,
   132→                    Err(err) => {
   133→                        increment_counter!(
   134→                            "pipeline_stage_errors",
   135→                            "stage" => stage.name(),
   136→                            "kind" => match &err {
   137→                                StageError::Transient(_) => "transient",
   138→                                StageError::Permanent(_) => "permanent",
   139→                            }
   140→                        );
   141→                        return Err(err);
   142→                    }
   143→                },
   144→                None => return Ok(None), // Already dropped
   145→            }
   146→        }
   147→        Ok(current)
   148→    }
   149→}
