   291→    /// Internal: spawn the concurrent worker tasks for the provided stream.
   292→    fn spawn_processing_loop<S>(
   293→        &self,
   294→        input: S,
   295→    ) -> JoinHandle<anyhow::Result<()>>
   296→    where
   297→        S: Stream<Item = SocialEvent> + Send + 'static,
   298→    {
   299→        let shutdown = self.shutdown.clone();
   300→        let pipeline = self.pipeline.clone();
   301→        let retry_backoff = self.cfg.retry_backoff;
   302→        let max_inflight = self.cfg.max_inflight;
   303→
   304→        tokio::spawn(async move {
   305→            let mut inflight: FuturesUnordered<_> = FuturesUnordered::new();
   306→            tokio::pin!(input);
   307→
   308→            loop {
   309→                select! {
   310→                    biased;
   311→
   312→                    _ = shutdown.notified() => {
   313→                        tracing::info!("shutdown signal received; draining inflight tasks");
   314→                        while inflight.next().await.is_some() {}
   315→                        return Ok(());
   316→                    }
   317→
   318→                    Some(res) = inflight.next(), if inflight.len() > 0 => {
   319→                        if let Err(err) = res {
   320→                            tracing::warn!("task failed: {err:?}");
   321→                        }
   322→                    }
   323→
   324→                    item = input.next(), if inflight.len() < max_inflight => {
   325→                        match item {
   326→                            Some(ev) => {
   327→                                let p = pipeline.clone();
   328→                                let shutdown_task = shutdown.clone();
   329→                                let fut = async move {
   330→                                    let enriched = p.execute((&ev).into()).await;
   331→                                    match enriched {
   332→                                        Ok(Some(out)) => {
   333→                                            counter!("events_ok").increment(1);
   334→                                            tracing::trace!("processed event {}", out.id);
   335→                                        }
   336→                                        Ok(None) => {
   337→                                            counter!("events_filtered").increment(1);
   338→                                        }
   339→                                        Err(StageError::Transient(_)) => {
   340→                                            histogram!("events_retry_backoff_ms")
   341→                                                .record(retry_backoff.as_millis() as f64);
   342→                                            tokio::time::sleep(retry_backoff).await;
   343→                                            // requeue by simply resubmitting the event
   344→                                            if !shutdown_task.is_notified() {
   345→                                                // naive requeue (could be improved with bounded channel)
   346→                                                p.execute((&ev).into()).await.ok();
   347→                                            }
   348→                                        }
   349→                                        Err(StageError::Permanent(_)) => {
   350→                                            counter!("events_skipped_permanent").increment(1);
   351→                                        }
   352→                                    }
   353→                                    Ok::<_, anyhow::Error>(())
   354→                                };
   355→                                inflight.push(fut);
   356→                            }
   357→                            None => {
   358→                                tracing::info!("input stream closed");
   359→                                break;
   360→                            }
   361→                        }
   362→                    }
   363→                }
   364→            }
   365→            // drain remaining
   366→            while inflight.next().await.is_some() {}
   367→            Ok(())
   368→        })
   369→    }
