   233→    /// or an unrecoverable error occurs.
   234→    #[instrument(skip(self))]
   235→    pub async fn run(mut self) -> Result<(), OrchestratorError> {
   236→        loop {
   237→            select! {
   238→                _ = self.shutdown_rx.recv() => {
   239→                    info!("shutdown signal received");
   240→                    return Err(OrchestratorError::Shutdown);
   241→                }
