     2→//! src/module_10.rs
     3→//!
     4→//! Dynamic enrichment pipeline with hot-swappable strategies.
     5→//! This module represents a self-contained “micro-pipeline” that can be embedded
     6→//! in any streaming consumer (e.g., a Kafka consumer task).  It demonstrates:
     7→//!   • Strategy Pattern for pluggable enrichment algorithms  
     8→//!   • Thread-safe hot-swap at runtime (no restart required)  
     9→//!   • Observability hooks (structured logging + metrics)  
    10→//!   • Graceful error handling and back-pressure aware execution
    11→//!
    12→//! The code is designed to be production-ready; it depends only on mature crates
    13→//! and is agnostic to the surrounding runtime (Tokio, async-std, etc.).
    14→//!
    15→//! # Usage
    16→//! ```rust,no_run
    17→//! use chirp_pulse::pipeline::{DynamicPipeline, ToxicityScorer, LanguageDetector};
    18→//!
    19→//! #[tokio::main(flavor = "multi_thread")]
    20→//! async fn main() -> anyhow::Result<()> {
    21→//!     let pipeline = DynamicPipeline::builder()
    22→//!         .with_stage("lang_detect", LanguageDetector::default())
    23→//!         .with_stage("toxicity", ToxicityScorer::default())
    24→//!         .build();
    25→//!
    26→//!     pipeline.run_stream(kafka_stream()).await?;
    27→//!     Ok(())
    28→//! }
    29→//! ```
    30→//!
    31→//! In production this module would live in its own crate; for brevity we expose
    32→//! everything under `crate::pipeline`.
