   144→/// Thread-safe collection of enrichment stages that can be updated at runtime.
   145→#[derive(Clone)]
   146→pub struct StageRegistry {
   147→    inner: Arc<RwLock<HashMap<&'static str, Arc<dyn EnrichmentStage>>>>,
   148→}
   149→
   150→impl StageRegistry {
   151→    pub fn new() -> Self {
   152→        Self {
   153→            inner: Arc::new(RwLock::new(HashMap::new())),
   154→        }
   155→    }
   156→
   157→    pub fn insert<S: EnrichmentStage>(&self, stage: S) {
   158→        let mut map = self.inner.write();
   159→        map.insert(stage.name(), Arc::new(stage));
   160→        info!(stage = %stage.name(), "registered enrichment stage");
   161→    }
   162→
   163→    pub fn remove(&self, name: &'static str) -> Option<Arc<dyn EnrichmentStage>> {
   164→        let mut map = self.inner.write();
   165→        let removed = map.remove(name);
   166→        if removed.is_some() {
   167→            warn!(stage = %name, "unregistered enrichment stage");
   168→        }
   169→        removed
   170→    }
   171→
   172→    pub fn list(&self) -> Vec<&'static str> {
   173→        self.inner.read().keys().copied().collect()
   174→    }
   175→
   176→    pub fn snapshot(&self) -> Vec<Arc<dyn EnrichmentStage>> {
   177→        self.inner.read().values().cloned().collect()
   178→    }
   179→}
