   181→/// Metrics emitted by the pipeline.
   182→#[derive(Debug, Clone)]
   183→pub struct PipelineMetrics {
   184→    pub processed: u64,
   185→    pub failed: u64,
   186→    pub lag_ms: u64,
   187→}
