   189→/// A dynamic, stoppable pipeline.
   190→///
   191→/// Internally it spins up an async task that:
   192→///   • reads from an upstream stream (user-supplied)  
   193→///   • applies currently registered stages in insertion order  
   194→///   • publishes enriched events to a downstream sender (user-supplied)
   195→pub struct DynamicPipeline {
   196→    stages: StageRegistry,
   197→    shutdown_tx: watch::Sender<bool>,
   198→    metrics_rx: watch::Receiver<PipelineMetrics>,
   199→    handle: JoinHandle<Result<()>>,
   200→}
   201→
   202→impl DynamicPipeline {
   203→    pub fn builder() -> PipelineBuilder {
   204→        PipelineBuilder::default()
   205→    }
   206→
   207→    /// Gracefully shuts down the pipeline, waiting for the internal task to
   208→    /// flush in-flight events (bounded by `grace_period`).
   209→    pub async fn stop(self, grace_period: Duration) -> Result<()> {
   210→        self.shutdown_tx.send_replace(true);
   211→        let res = tokio::time::timeout(grace_period, self.handle)
   212→            .await
   213→            .map_err(|_| PipelineError::Cancelled)??;
   214→        Ok(res)
   215→    }
   216→
   217→    /// Returns a read-only view into live metrics.
   218→    pub fn metrics(&self) -> watch::Receiver<PipelineMetrics> {
   219→        self.metrics_rx.clone()
   220→    }
   221→
   222→    /// Exposes the underlying registry for hot-swapping.
   223→    pub fn registry(&self) -> StageRegistry {
   224→        self.stages.clone()
   225→    }
   226→}
