   228→/// Builder pattern for ergonomic pipeline creation.
   229→#[derive(Default)]
   230→pub struct PipelineBuilder {
   231→    stages: StageRegistry,
   232→}
   233→
   234→impl PipelineBuilder {
   235→    pub fn with_stage<S: EnrichmentStage>(mut self, _id: &'static str, stage: S) -> Self {
   236→        self.stages.insert(stage);
   237→        self
   238→    }
   239→
   240→    /// Construct and spawn the pipeline.
   241→    ///
   242→    /// `input` – Any async stream that yields `SocialEvent`s  
   243→    /// `output` – An `mpsc::Sender` where enriched events will be pushed
   244→    pub fn spawn<I>(
   245→        self,
   246→        mut input: I,
   247→        output: mpsc::Sender<SocialEvent>,
   248→    ) -> DynamicPipeline
   249→    where
   250→        I: futures_core::Stream<Item = SocialEvent> + Send + 'static,
   251→    {
   252→        let stages = self.stages;
   253→        let (shutdown_tx, mut shutdown_rx) = watch::channel(false);
   254→
   255→        let metrics = PipelineMetrics {
   256→            processed: 0,
   257→            failed: 0,
   258→            lag_ms: 0,
   259→        };
   260→        let (metrics_tx, metrics_rx) = watch::channel(metrics.clone());
   261→
   262→        let handle: JoinHandle<Result<()>> = tokio::spawn(async move {
   263→            let counter = AtomicU64::new(0);
   264→            let mut most_recent_ts = Instant::now();
   265→
   266→            loop {
   267→                select! {
   268→                    _ = shutdown_rx.changed() => {
   269→                        info!("pipeline shutdown requested");
   270→                        break;
   271→                    },
   272→                    maybe_ev = input.next() => {
   273→                        let mut ev = match maybe_ev {
   274→                            Some(ev) => ev,
   275→                            None => break, // upstream closed
   276→                        };
   277→
   278→                        let start = Instant::now();
   279→                        let mut failed_stage = None;
   280→
   281→                        for stage in stages.snapshot() {
   282→                            if let Err(e) = stage.process(&mut ev).await {
   283→                                failed_stage = Some((stage.name(), e));
   284→                                break;
   285→                            }
   286→                        }
   287→
   288→                        if let Some((name, err)) = failed_stage {
   289→                            error!(stage = %name, error = %err, id=%ev.id, "event failed");
   290→                            metrics_tx.send_if_modified(|m| {
   291→                                m.failed += 1;
   292→                                true
   293→                            });
   294→                            continue; // Skip publishing bad event
   295→                        }
   296→
   297→                        // Publish enriched event downstream (may exert back-pressure).
   298→                        if output.send(ev).await.is_err() {
   299→                            return Err(PipelineError::ChannelClosed);
   300→                        }
   301→
   302→                        let elapsed = start.elapsed().as_millis() as u64;
   303→                        most_recent_ts = Instant::now();
   304→                        let processed = counter.fetch_add(1, Ordering::Relaxed) + 1;
   305→
   306→                        metrics_tx.send_if_modified(|m| {
   307→                            m.processed = processed;
   308→                            m.lag_ms = elapsed;
   309→                            true
   310→                        });
   311→                    }
   312→                }
   313→            }
   314→
   315→            let runtime = most_recent_ts.elapsed();
   316→            info!(
   317→                processed = counter.load(Ordering::Relaxed),
   318→                runtime_ms = runtime.as_millis(),
   319→                "pipeline terminated"
   320→            );
   321→            Ok(())
   322→        });
   323→
   324→        DynamicPipeline {
   325→            stages,
   326→            shutdown_tx,
   327→            metrics_rx,
   328→            handle,
   329→        }
   330→    }
