ntiment scores).\n    pub const ENRICHED_EVENTS: &str  = \"chirp.enriched.events\";\n    /// Compact facts about influencer relationships.\n    pub const GRAPH_UPDATES: &str    = \"chirp.graph.updates\";\n    /// Dead-letter queue for poison pills.\n    pub const DLQ: &str              = \"chirp.dlq\";\n}\n\n/// Apache Iceberg catalog and warehouse settings.\npub mod iceberg {\n    /// Warehouse directory where tables are materialised.\n    pub const WAREHOUSE_DIR: &str = \"s3://chirp-pulse-lake\";\n\n    /// Name of the metadata catalog (glue/hive) that tables register with.\n    pub const CATALOG_NAME: &str  = \"chirp_catalog\";\n}\n\n/// Default concurrency knobs -------------------------------------------------\n\n/// How many threads a typical ingest worker will spawn when no explicit\n/// `RAYON_NUM_THREADS` or per-job override is supplied.\npub const DEFAULT_INGEST_PARALLELISM: NonZeroUsize =\n    // SAFETY: 4 is non-zero by definition.\n    unsafe { NonZeroUsize::new_unchecked(4) };\n\n/// Maximum size of an in-memory batch before it is flushed downstream.\npub const MAX_BATCH_SIZE: usize = 5_000;\n\n/// Retry & back-off strategy --------------------------------------------------\n\n/// Number of times a non-fatal Kafka produce error is retried before the\n/// message is sent to the DLQ.\npub const PRODUCER_RETRY_ATTEMPTS: u32 = 5;\n\n/// Initial back-off delay for retrying transient network or broker failures.\npub const INITIAL_BACKOFF: Duration = Duration::from_millis(200);\n\n/// Maximum back-off delay (capped exponential).\npub const MAX_BACKOFF: Duration = Duration::from_secs(30);\n\n/// Languages supported by the *default* language-detection model.\n/// More can be added dynamically via plugin loading.\npub static SUPPORTED_LANGUAGES: &[&str] = &[\n    \"en\", // English\n    \"es\", // Spanish\n    \"fr\", // French\n    \"de\", // German\n    \"pt\", // Portuguese\n    \"ja\", // Japanese\n    \"ko\", // Korean\n    \"zh\", // Chinese (simplified & traditional)\n];\n\n/// Observability --------------------------------------------------------------\n\n/// Prometheus metrics namespace label.\npub const METRICS_NAMESPACE: &str = \"chirp_pulse\";\n\n/// Jaeger/OTLP tracing service name (overrides default from tracer impl).\npub const TRACING_SERVICE_NAME: &str = \"chirp-pulse\";\n\n/// Helper API -----------------------------------------------------------------\n\n/// Return the service's user-agent string used when querying remote HTTP\n/// endpoints.  Format: `SERVICE_NAME/VERSION (commit SHA)`.\n///\n/// The git commit hash is embedded at compile-time via `vergen` build-script,\n/// falling back to `UNKNOWN` if unavailable.\npub fn user_agent() -> String {\n    static GIT_SHA: Lazy<&'static str> = Lazy::new(|| {\n        option_env!(\"VERGEN_GIT_SHA\").unwrap_or(\"UNKNOWN\")\n    });\n\n    format!(\"{SERVICE_NAME}/{VERSION} ({})\", *GIT_SHA)\n}\n\n#[cfg(test)]\nmod tests {\n    use super::*;\n\n    #[test]\n    fn user_agent_contains_version_and_sha() {\n        let ua = user_agent();\n        assert!(ua.contains(VERSION));\n        assert!(ua.contains(SERVICE_NAME));\n    }\n\n    #[test]\n    fn kafka_brokers_env_override() {\n        const TEST_VAL: &str = \"foo:123,bar:456\";\n\n        // Setting env vars inside tests is safe as long as we do it before\n        // the first access to the Lazy; hence we spawn a new thread.\n        std::thread::spawn(|| {\n            std::env::set_var(\"CHIRP_PULSE_KAFKA_BROKERS\", TEST_VAL);\n            // Force re-evaluation in this thread only.\n            let brokers = std::env::var(\"CHIRP_PULSE_KAFKA_BROKERS\").unwrap();\n            assert_eq!(brokers, TEST_VAL);\n        }).join().unwrap();\n    }\n}\n```", "numLines": 143, "startLine": 1, "totalLines": 143}}

1→//! module_30 - Data Quality Gate & Stream Monitor
     2→//! This module provides a pluggable data-quality validation engine that can be wired
     3→//! directly into Kafka consumer loops.
     4→//! It is designed to run in the ChirpPulse real-time stream processing services.
     5→
     6→use std::{
     7→    collections::{HashMap, HashSet},
     8→    sync::Arc,
     9→    time::Duration,
    10→};
    11→
    12→use async_trait::async_trait;
    13→use chrono::{DateTime, Utc};
    14→use humantime::format_duration;
    15→use log::{debug, error, info, warn};
    16→use metrics::{counter, gauge, histogram};
    17→use once_cell::sync::Lazy;
    18→use regex::Regex;
    19→use serde_json::Value;
    20→use thiserror::Error;
    21→use tokio::{
    22→    select,
    23→    sync::{mpsc, Semaphore},
    24→    task::JoinHandle,
    25→    time::{interval, sleep, Instant},
    26→};
    27→
    28→/// Maximum number of concurrent validation jobs.
    29→/// (safeguard to protect service from spikes)
    30→const MAX_CONCURRENCY: usize = 256;
    31→
    32→/// Interval at which internal health metrics are flushed.
    33→const METRIC_FLUSH_INTERVAL: Duration = Duration::from_secs(30);
    34→
    35→/// Wrapper around serde_json::Value that represents an incoming social event.
    36→#[derive(Debug, Clone)]
    37→pub struct SocialRecord {
    38→    pub raw: Value,
    39→    pub received_at: DateTime<Utc>,
    40→    /// Topic name (twitter, reddit, etc.)
    41→    pub source_topic: String,
    42→    /// Kafka offset (or any position marker)
    43→    pub offset: i64,
    44→}
    45→
    46→#[derive(Debug, Error)]
    47→pub enum QualityError {
    48→    #[error("required field `{0}` missing")]
    49→    MissingField(String),
    50→    #[error("field `{0}` failed regex validation")]
    51→    RegexMismatch(String),
    52→    #[error("language detection mismatch: expected {expected}, got {actual}")]
    53→    LanguageMismatch { expected: String, actual: String },
    54→    #[error("custom engine error: {0}")]
    55→    Custom(String),
    56→}
    57→
    58→#[async_trait]
    59→pub trait DataQualityCheck: Send + Sync {
    60→    /// Name of the check (used for logging & metrics).
    61→    fn name(&self) -> &'static str;
    62→
    63→    /// Validate the provided record.
    64→    async fn validate(&self, record: &SocialRecord) -> Result<(), QualityError>;
    65→}
    66→
    67→/// Data quality check that asserts the presence of a non-empty field.
    68→pub struct RequiredFieldCheck {
    69→    field: &'static str,
    70→}
    71→impl RequiredFieldCheck {
    72→    pub fn new(field: &'static str) -> Self {
    73→        Self { field }
    74→    }
    75→}
    76→
    77→#[async_trait]
    78→impl DataQualityCheck for RequiredFieldCheck {
    79→    fn name(&self) -> &'static str {
    80→        "required_field"
    81→    }
    82→
    83→    async fn validate(&self, record: &SocialRecord) -> Result<(), QualityError> {
    84→        match record.raw.get(self.field) {
    85→            Some(v) if !v.is_null() => Ok(()),
    86→            _ => Err(QualityError::MissingField(self.field.into())),
    87→        }
    88→    }
    89→}
    90→
    91→/// Data quality check that applies a regex to a string field.
    92→pub struct RegexFieldCheck {
    93→    field: &'static str,
    94→    regex: &'static Regex,
    95→}
    96→
    97→impl RegexFieldCheck {
    98→    pub const fn new(field: &'static str, regex: &'static Regex) -> Self {
    99→        Self { field, regex }
   100→    }
   101→}
   102→
   103→#[async_trait]
   104→impl DataQualityCheck for RegexFieldCheck {
   105→    fn name(&self) -> &'static str {
   106→        "regex_field"
   107→    }
   108→
   109→    async fn validate(&self, record: &SocialRecord) -> Result<(), QualityError> {
   110→        match record.raw.get(self.field) {
   111→            Some(Value::String(s)) if self.regex.is_match(s) => Ok(()),
   112→            _ => Err(QualityError::RegexMismatch(self.field.into())),
   113→        }
   114→    }
   115→}
   116→
   117→/// Central engine that orchestrates execution of data-quality checks for incoming records.
   118→pub struct QualityGate {
   119→    checks: Vec<Arc<dyn DataQualityCheck>>,
   120→    semaphore: Arc<Semaphore>,
   121→    reporter: mpsc::UnboundedSender<QualityReport>,
   122→}
   123→
   124→impl QualityGate {
   125→    /// Build a new QualityGate with the provided checks.
   126→    pub fn new(checks: Vec<Arc<dyn DataQualityCheck>>) -> Self {
   127→        let (tx, rx) = mpsc::unbounded_channel();
   128→        let gate = Self {
   129→            checks,
   130→            semaphore: Arc::new(Semaphore::new(MAX_CONCURRENCY)),
   131→            reporter: tx,
   132→        };
   133→        gate.spawn_report_collector(rx);
   134→        gate
   135→    }
   136→
   137→    /// Validates a batch of social records concurrently. Returns handles that can be awaited
   138→    /// for completion.
   139→    pub fn validate_batch(&self, batch: Vec<SocialRecord>) -> Vec<JoinHandle<()>> {
   140→        let mut handles = Vec::with_capacity(batch.len());
   141→
   142→        for record in batch {
   143→            let permit = match self.semaphore.clone().try_acquire_owned() {
   144→                Ok(p) => p,
   145→                Err(_) => {
   146→                    // Should be exceedingly rare, but ensures we never panic.
   147→                    warn!("QualityGate semaphore at capacity; stalling new validations");
   148→                    // Acquire asynchronously to wait.
   149→                    let semaphore = self.semaphore.clone();
   150→                    handles.push(tokio::spawn(async move {
   151→                        let _permit = semaphore.acquire().await;
   152→                        drop(_permit);
   153→                    }));
   154→                    continue;
   155→                }
   156→            };
   157→
   158→            let checks = self.checks.clone();
   159→            let tx = self.reporter.clone();
   160→
   161→            handles.push(tokio::spawn(async move {
   162→                let _alive_permit = permit; // keep permit alive for duration
   163→                let mut issues = Vec::new();
   164→
   165→                for check in &checks {
   166→                    match check.validate(&record).await {
   167→                        Ok(()) => {
   168→                            counter!(
   169→                                "chirppulse_quality_check_pass_total",
   170→                                1,
   171→                                "check" => check.name()
   172→                            );
   173→                        }
   174→                        Err(err) => {
   175→                            counter!(
   176→                                "chirppulse_quality_check_fail_total",
   177→                                1,
   178→                                "check" => check.name(),
   179→                                "source_topic" => record.source_topic.as_str()
   180→                            );
   181→                            issues.push(err);
   182→                        }
   183→                    }
   184→                }
   185→
   186→                let report = QualityReport {
   187→                    record_meta: RecordMeta {
   188→                        source_topic: record.source_topic,
   189→                        offset: record.offset,
   190→                        received_at: record.received_at,
   191→                    },
   192→                    issues,
   193→                };
   194→
   195→                if let Err(e) = tx.send(report) {
   196→                    error!("quality report channel closed unexpectedly: {e}");
   197→                }
   198→            }));
   199→        }
   200→
   201→        handles
   202→    }
   203→
   204→    /// Background task that aggregates and dumps quality reports.
   205→    fn spawn_report_collector(&self, mut rx: mpsc::UnboundedReceiver<QualityReport>) {
   206→        tokio::spawn(async move {
   207→            let mut buffer: Vec<QualityReport> = Vec::with_capacity(10_000);
   208→            let mut ticker = interval(METRIC_FLUSH_INTERVAL);
   209→
   210→            loop {
   211→                select! {
   212→                    maybe_report = rx.recv() => {
   213→                        match maybe_report {
   214→                            Some(report) => buffer.push(report),
   215→                            None => {
   216→                                debug!("QualityGate report channel closed; terminating collector");
   217→                                break;
   218→                            }
   219→                        }
   220→                    }
   221→                    _ = ticker.tick() => {
   222→                        if !buffer.is_empty() {
   223→                            Self::flush_reports(std::mem::take(&mut buffer));
   224→                        }
   225→                    }
   226→                }
   227→            }
   228→
   229→            // final flush
   230→            if !buffer.is_empty() {
   231→                Self::flush_reports(buffer);
   232→            }
   233→        });
   234→    }
   235→
   236→    fn flush_reports(batch: Vec<QualityReport>) {
   237→        let total_issues: usize = batch.iter().map(|r| r.issues.len()).sum();
   238→        gauge!("chirppulse_quality_pending_reports", 0.0);
   239→        histogram!("chirppulse_quality_issues_per_batch", total_issues as f64);
   240→
   241→        if total_issues > 0 {
   242→            info!(
   243→                "QualityGate flushed {} problematic records containing {} total issues",
   244→                batch.len(),
   245→                total_issues
   246→            );
   247→            // In production this would be persisted to a DLQ, external store, or alerting bus.
   248→            for report in &batch {
   249→                for issue in &report.issues {
   250→                    warn!(
   251→                        "[DQ] topic={} offset={} issue={}",
   252→                        report.record_meta.source_topic, report.record_meta.offset, issue
   253→                    );
   254→                }
   255→            }
   256→        } else {
   257→            debug!(
   258→                "QualityGate flushed {} clean records (no issues)",
   259→                batch.len()
   260→            );
   261→        }
   262→    }
   263→}
