   265→/// Metadata we carry around for observability purposes.
   266→/// Kept separate from the `SocialRecord` to avoid cloning the full JSON document.
   267→#[derive(Debug, Clone)]
   268→pub struct RecordMeta {
   269→    pub source_topic: String,
   270→    pub offset: i64,
   271→    pub received_at: DateTime<Utc>,
   272→}
   273→
   274→/// A single validation report for a social record.
   275→#[derive(Debug)]
   276→pub struct QualityReport {
   277→    pub record_meta: RecordMeta,
   278→    pub issues: Vec<QualityError>,
   279→}
