   281→/// A small helper that encapsulates an exponential back-off policy.
   282→///
   283→/// This is useful when interacting with external systems (e.g. Kafka, S3)
   284→/// where transient failures are expected during high traffic peaks.
   285→pub struct Backoff {
   286→    next_delay: Duration,
   287→    max_delay: Duration,
   288→}
   289→
   290→impl Backoff {
   291→    pub const fn new(initial: Duration, max_delay: Duration) -> Self {
   292→        Self {
   293→            next_delay: initial,
   294→            max_delay,
   295→        }
   296→    }
   297→
   298→    /// Wait for the current backoff delay, then exponentially increase it.
   299→    pub async fn snooze(&mut self) {
   300→        let wait = self.next_delay.min(self.max_delay);
   301→        debug!("backoff sleeping for {}", format_duration(wait));
   302→        sleep(wait).await;
   303→        self.next_delay = (self.next_delay * 2).min(self.max_delay);
   304→    }
   305→
   306→    /// Reset the backoff delay to initial value.
   307→    pub fn reset(&mut self, initial: Duration) {
   308→        self.next_delay = initial;
   309→    }
   310→}
   311→
   312→/// A simple health-check watchdog that notifies if consumer lag grows beyond thresholds.
   313→pub struct LagMonitor {
   314→    window: Duration,
   315→    critical_threshold: u64,
   316→    last_offsets: HashMap<String, i64>,
   317→    last_check: Instant,
   318→}
   319→
   320→impl LagMonitor {
   321→    pub fn new(window: Duration, critical_threshold: u64) -> Self {
   322→        Self {
   323→            window,
   324→            critical_threshold,
   325→            last_offsets: HashMap::new(),
   326→            last_check: Instant::now(),
   327→        }
   328→    }
   329→
   330→    /// Update the latest committed offset for the given topic.
   331→    pub fn record_offset(&mut self, topic: &str, offset: i64) {
   332→        self.last_offsets.insert(topic.to_owned(), offset);
   333→    }
   334→
   335→    /// Returns true if lag is considered healthy.
   336→    pub fn is_healthy(&mut self, fetch_lag: impl Fn(&str) -> Option<u64>) -> bool {
   337→        if self.last_check.elapsed() < self.window {
   338→            return true;
   339→        }
   340→        self.last_check = Instant::now();
   341→
   342→        for (topic, offset) in &self.last_offsets {
   343→            if let Some(lag) = fetch_lag(topic) {
   344→                gauge!("chirppulse_consumer_lag", lag as f64, "topic" => topic.clone());
   345→
   346→                if lag > self.critical_threshold {
   347→                    error!(
   348→                        "LagMonitor detected critical lag on topic `{}` ({} messages behind)",
   349→                        topic, lag
   350→                    );
   351→                    return false;
   352→                } else {
   353→                    debug!(
   354→                        "LagMonitor topic `{}` healthy (lag = {})",
   355→                        topic, lag
   356→                    );
   357→                }
   358→            } else {
   359→                warn!(
   360→                    "LagMonitor unable to fetch lag for topic `{}`; assuming unhealthy",
   361→                    topic
   362→                );
   363→                return false;
   364→            }
   365→        }
   366→        true
   367→    }
   368→}
   369→
   370→// Pre-compiled regular expressions to prevent recompilation at runtime.
   371→static MENTION_RE: Lazy<Regex> = Lazy::new(|| Regex::new(r"^@\w{1,15}$").unwrap());
