   373→/// Example of how to wire everything into an asynchronous consumer loop.
   374→#[cfg(test)]
   375→mod tests {
   376→    use super::*;
   377→    use serde_json::json;
   378→
   379→    #[tokio::test]
   380→    async fn validate_required_field() {
   381→        let checks: Vec<Arc<dyn DataQualityCheck>> =
   382→            vec![Arc::new(RequiredFieldCheck::new("text"))];
   383→
   384→        let gate = QualityGate::new(checks);
   385→
   386→        let record_ok = SocialRecord {
   387→            raw: json!({"text": "hello world"}),
   388→            received_at: Utc::now(),
   389→            source_topic: "twitter_dev".into(),
   390→            offset: 42,
   391→        };
   392→
   393→        let record_bad = SocialRecord {
   394→            raw: json!({"foo": "bar"}),
   395→            received_at: Utc::now(),
   396→            source_topic: "twitter_dev".into(),
   397→            offset: 43,
   398→        };
   399→
   400→        let handles = gate.validate_batch(vec![record_ok, record_bad]);
   401→        for h in handles {
   402→            h.await.unwrap();
   403→        }
   404→    }
   405→
   406→    #[tokio::test]
   407→    async fn backoff_behaviour() {
   408→        let mut backoff = Backoff::new(Duration::from_millis(10), Duration::from_millis(80));
   409→        for expected in [10, 20, 40, 80, 80] {
   410→            let before = Instant::now();
   411→            backoff.snooze().await;
   412→            let slept = before.elapsed().as_millis();
   413→            assert!(slept as u64 >= expected);
   414→        }
   415→        backoff.reset(Duration::from_millis(10));
   416→        assert_eq!(backoff.next_delay, Duration::from_millis(10));
   417→    }
   418→}

