     2→//! src/module_56.rs
     3→//!
     4→//! Reconfigurable, strategy-pattern driven sentiment engine used by
     5→//! ChirpPulse’s enrichment microservice.  The engine consumes raw social
     6→//! events from an async channel, enriches them with a sentiment score using the
     7→//! currently active strategy, and publishes the enriched payload downstream.
     8→//!
     9→//! The strategy can be hot-swapped at runtime by editing a single TOML config
    10→//! file.  A lightweight file-watcher notifies the engine of configuration
    11→//! changes and the strategy is swapped without interrupting the data-flow.
    12→//!
    13→//! Build-time feature flags make the module easy to mock in unit tests while
    14→//! still using real Kafka producers/consumers in production.
    15→//
    16→// --------------- Crate Dependencies ---------------
    17→// tokio           = { version = "1.34", features = ["rt", "fs", "macros"] }
    18→// serde           = { version = "1.0",  features = ["derive"] }
    19→// serde_json      = "1.0"
    20→// toml            = "0.7"
    21→// async-trait     = "0.1"
    22→// anyhow          = "1.0"
    23→// notify          = "6.1"
    24→// tracing         = "0.1"
    25→//
    26→// Optional (behind `kafka` feature):
    27→// rdkafka         = { version = "0.34", optional = true, features = ["tokio"] }
    28→//
    29→// --------------------------------------------------
    30→
    31→use std::{
    32→    path::{Path, PathBuf},
    33→    sync::Arc,
    34→    time::{Duration, Instant},
    35→};
