    49→/// Maximum number of inflight events the channel will buffer before back-pressuring
    50→const CHANNEL_CAPACITY: usize = 16_384;
    51→
    52→/// Public API surface
    53→pub mod api {
    54→    use super::*;
    55→
    56→    /// Raw, unprocessed social-stream event
    57→    #[derive(Debug, Clone, Serialize, Deserialize)]
