    59→        pub id: String,
    60→        pub user_id: String,
    61→        pub text: String,
    62→        pub timestamp: i64,
    63→        // Additional metadata elided
    64→    }
    65→
    66→    /// Enriched event emitted by the sentiment engine
    67→    #[derive(Debug, Clone, Serialize, Deserialize)]
    68→    pub struct EnrichedEvent {
    69→        pub id: String,
    70→        pub user_id: String,
    71→        pub text: String,
