    76→    }
    77→}
    78→
    79→// --------------- Strategy Pattern Implementation -----------------
    80→
    81→#[async_trait]
    82→pub trait SentimentStrategy: Send + Sync {
    83→    /// Human-readable identifier (used for telemetry & auditing)
    84→    fn version(&self) -> &str;
    85→
    86→    /// Perform the analysis.  Must be fast (<1 ms) or spawn its own blocking task.
    87→    async fn score(&self, text: &str) -> Result<f32>;
    88→}
    89→
    90→/// Extremely naive, rule-based heuristic sentiment scorer.
    91→/// Suitable as a safe-mode fallback when heavy ML models fail.
    92→pub struct RuleBasedStrategy;
    93→
    94→#[async_trait]
    95→impl SentimentStrategy for RuleBasedStrategy {
    96→    fn version(&self) -> &str {
    97→        "rule-based-v1"
    98→    }
    99→
   100→    async fn score(&self, text: &str) -> Result<f32> {
   101→        let lowered = text.to_ascii_lowercase();
   102→        let pos = ["good", "love", "awesome", "yay"]
   103→            .iter()
   104→            .filter(|w| lowered.contains(*w))
   105→            .count() as f32;
   106→        let neg = ["bad", "hate", "terrible", "boo"]
   107→            .iter()
   108→            .filter(|w| lowered.contains(*w))
   109→            .count() as f32;
   110→
   111→        Ok(match (pos - neg).clamp(-5.0, 5.0) {
   112→            x if x > 0.0 => x / 5.0,
   113→            x if x < 0.0 => x / 5.0,
   114→            _ => 0.0,
   115→        })
   116→    }
   117→}
