     2→//! ChirpPulse – Data-Quality & Monitoring Module
     3→//! ---------------------------------------------
     4→//! `module_29` is responsible for executing a configurable chain of
     5→//! data-quality checks against streaming social records and exposing
     6→//! real-time metrics about their outcome.  Checks can be swapped or
     7→//! re-configured at run-time without stopping the stream.
     8→//!
     9→//! Key capabilities
    10→//! • Strategy pattern for pluggable checks  
    11→//! • Parallel record validation (Rayon)  
    12→//! • Async stream wiring (Tokio)  
    13→//! • Metrics emission (metrics crate)  
    14→//! • Hot-reloadable configuration (watch channel)
    15→
    16→use std::{
    17→    sync::Arc,
    18→    time::{Duration, SystemTime},
    19→};
    20→
    21→use parking_lot::RwLock;
    22→use rayon::prelude::*;
    23→use serde::{Deserialize, Serialize};
    24→use thiserror::Error;
    25→use tokio::{
    26→    select,
    27→    sync::{mpsc, watch},
    28→    task,
    29→    time,
    30→};
    31→
    32→/// A single social message after initial ingestion.
    33→/// Lightweight by design; heavy payloads live in object storage.
    34→#[derive(Debug, Serialize, Deserialize, Clone)]
    35→pub struct SocialRecord {
    36→    pub id: String,
    37→    pub timestamp: SystemTime,
    38→    pub text: String,
    39→    pub lang: Option<String>,
    40→    pub toxicity_score: Option<f32>,
    41→}
    42→
    43→/// Top-level error for any data-quality violation.
    44→#[derive(Debug, Error)]
    45→pub enum QualityError {
    46→    #[error("field `{0}` missing")]
    47→    MissingField(&'static str),
    48→
    49→    #[error("invalid language code `{0}`")]
    50→    InvalidLanguage(String),
    51→
    52→    #[error("toxicity {actual:.2} exceeds threshold {max:.2}")]
    53→    ToxicityExceeded { actual: f32, max: f32 },
    54→
    55→    #[error("unknown validation error")]
    56→    Other(#[from] anyhow::Error),
    57→}
    58→
    59→/// Strategy: anything that can validate a record.
    60→pub trait DataQualityCheck: Send + Sync {
    61→    fn name(&self) -> &'static str;
    62→    fn check(&self, record: &SocialRecord) -> Result<(), QualityError>;
    63→}
    64→
    65→/// Ensures mandatory fields are present.
    66→pub struct SchemaCheck;
    67→
    68→impl DataQualityCheck for SchemaCheck {
    69→    fn name(&self) -> &'static str {
    70→        "schema_check"
    71→    }
    72→
    73→    fn check(&self, record: &SocialRecord) -> Result<(), QualityError> {
    74→        if record.id.is_empty() {
    75→            return Err(QualityError::MissingField("id"));
    76→        }
    77→        if record.text.is_empty() {
    78→            return Err(QualityError::MissingField("text"));
    79→        }
    80→        Ok(())
    81→    }
    82→}
    83→
    84→/// Verifies language tag is ISO-639 compliant.
    85→pub struct LanguageCheck;
    86→
    87→impl DataQualityCheck for LanguageCheck {
    88→    fn name(&self) -> &'static str {
    89→        "language_check"
    90→    }
    91→
    92→    fn check(&self, record: &SocialRecord) -> Result<(), QualityError> {
    93→        if let Some(ref lang) = record.lang {
    94→            if lang.len() != 2 || !lang.chars().all(|c| c.is_ascii_alphabetic()) {
    95→                return Err(QualityError::InvalidLanguage(lang.clone()));
    96→            }
    97→        }
    98→        Ok(())
    99→    }
   100→}
   101→
   102→/// Fails messages that exceed a configurable toxicity threshold.
   103→pub struct ToxicityThresholdCheck {
   104→    max: f32,
   105→}
   106→
   107→impl ToxicityThresholdCheck {
   108→    pub fn new(max: f32) -> Self {
   109→        Self { max }
   110→    }
   111→}
   112→
   113→impl DataQualityCheck for ToxicityThresholdCheck {
   114→    fn name(&self) -> &'static str {
   115→        "toxicity_threshold_check"
   116→    }
   117→
   118→    fn check(&self, record: &SocialRecord) -> Result<(), QualityError> {
   119→        if let Some(actual) = record.toxicity_score {
   120→            if actual > self.max {
   121→                return Err(QualityError::ToxicityExceeded {
   122→                    actual,
   123→                    max: self.max,
   124→                });
   125→            }
   126→        }
   127→        Ok(())
   128→    }
   129→}
   130→
   131→/// Public handle that owns the current validator chain.
   132→#[derive(Clone)]
   133→pub struct DataQualityEngine {
   134→    checks: Arc<RwLock<Vec<Arc<dyn DataQualityCheck>>>>,
   135→}
   136→
   137→impl Default for DataQualityEngine {
   138→    fn default() -> Self {
   139→        Self {
   140→            checks: Arc::new(RwLock::new(vec![
   141→                Arc::new(SchemaCheck),
   142→                Arc::new(LanguageCheck),
   143→                Arc::new(ToxicityThresholdCheck::new(0.85)),
   144→            ])),
   145→        }
   146→    }
   147→}
   148→
   149→impl DataQualityEngine {
   150→    /// Replace the full validator chain atomically.
   151→    pub fn swap_checks(&self, new_checks: Vec<Arc<dyn DataQualityCheck>>) {
   152→        *self.checks.write() = new_checks;
   153→    }
   154→
   155→    /// Validate a slice of records in parallel, returning a tuple:
   156→    ///  (passed, failed_with_errors)
   157→    pub fn validate_batch(
   158→        &self,
   159→        records: &[SocialRecord],
   160→    ) -> (Vec<SocialRecord>, Vec<(SocialRecord, Vec<QualityError>)>) {
   161→        let checks = self.checks.read().clone(); // snapshot
   162→
   163→        records
   164→            .par_iter()
   165→            .map(|rec| {
   166→                let mut errors = Vec::new();
   167→                for check in &checks {
   168→                    if let Err(e) = check.check(rec) {
   169→                        errors.push(e);
   170→                    }
   171→                }
   172→                if errors.is_empty() {
   173→                    Left(rec.clone())
   174→                } else {
   175→                    Right((rec.clone(), errors))
